import{_ as i,a as s,b as r,c as a,d as t,e as n,f as o,g as d}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as l,o as u,c as p,a2 as c}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Index distribué fédéré","description":"","frontmatter":{},"headers":[],"relativePath":"fr-FR/Other/federated-distributed-index.md","filePath":"fr-FR/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),h={name:"fr-FR/Other/federated-distributed-index.md"};function m(f,e,v,g,b,x){return u(),p("div",null,[...e[0]||(e[0]=[c('<h1 id="index-distribue-federe" tabindex="-1">Index distribué fédéré <a class="header-anchor" href="#index-distribue-federe" aria-label="Permalink to &quot;Index distribué fédéré&quot;">​</a></h1><p>L’index distribué fédéré permet à plusieurs sites ImgBed de partager leurs listes de fichiers.</p><p>En pratique :</p><ul><li>Vous pouvez partager certains dossiers de votre site avec d’autres personnes.</li><li>Vous pouvez rejoindre le nœud d’une autre personne et synchroniser sa liste partagée dans votre panneau.</li><li>Les fichiers fédérés servent à parcourir, rechercher, prévisualiser et copier des liens. Ils ne sont pas réimportés dans votre propre stockage.</li></ul><h2 id="ou-configurer" tabindex="-1">Où configurer <a class="header-anchor" href="#ou-configurer" aria-label="Permalink to &quot;Où configurer&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Paramètres système -&gt; Autres paramètres -&gt; Index distribué fédéré</span></span></code></pre></div><p><img src="'+i+`" alt="Nœud local" loading="lazy"></p><p>La page comporte trois onglets :</p><table tabindex="0"><thead><tr><th>Onglet</th><th>Usage</th></tr></thead><tbody><tr><td>Nœud local</td><td>Configurer votre nœud, le domaine public, les dossiers partagés et l’index sortant</td></tr><tr><td>Nœuds rejoints</td><td>Gérer les nœuds d’autres sites que vous suivez</td></tr><tr><td>Demandes vers mon nœud</td><td>Gérer les demandes d’autres personnes souhaitant rejoindre votre nœud</td></tr></tbody></table><h2 id="configuration-initiale" tabindex="-1">Configuration initiale <a class="header-anchor" href="#configuration-initiale" aria-label="Permalink to &quot;Configuration initiale&quot;">​</a></h2><ol><li>Ouvrez <code>Nœud local</code>.</li><li>Activez <code>Activer</code>.</li><li>Choisissez les dossiers à partager dans <code>Dossiers de synchronisation</code>.</li><li>Cliquez sur <code>Mettre à jour l’index sortant</code>.</li><li>Si ImgBed détecte un changement de domaine, confirmez que le domaine actuel est bien le domaine de production.</li></ol><p>Vous pouvez choisir plusieurs dossiers. Si la liste est vide, tous les dossiers sont partagés.</p><h2 id="nœud-local" tabindex="-1">Nœud local <a class="header-anchor" href="#nœud-local" aria-label="Permalink to &quot;Nœud local&quot;">​</a></h2><h3 id="domaine-public" tabindex="-1">Domaine public <a class="header-anchor" href="#domaine-public" aria-label="Permalink to &quot;Domaine public&quot;">​</a></h3><p>Le domaine public est l’adresse utilisée par les autres nœuds pour accéder à votre site.</p><p>ImgBed la détecte automatiquement. En général, vous n’avez rien à saisir. Une confirmation est demandée lors de la première mise à jour de l’index ou après un changement de domaine.</p><h3 id="dossiers-de-synchronisation" tabindex="-1">Dossiers de synchronisation <a class="header-anchor" href="#dossiers-de-synchronisation" aria-label="Permalink to &quot;Dossiers de synchronisation&quot;">​</a></h3><p>Ces dossiers déterminent quels fichiers sont partagés.</p><p>Exemple :</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>Dans ce cas, les autres nœuds ne voient que les fichiers de ces deux répertoires.</p><h3 id="mettre-a-jour-l-index-sortant" tabindex="-1">Mettre à jour l’index sortant <a class="header-anchor" href="#mettre-a-jour-l-index-sortant" aria-label="Permalink to &quot;Mettre à jour l’index sortant&quot;">​</a></h3><p>Cette action met à jour la liste de fichiers que les autres nœuds peuvent synchroniser depuis votre site.</p><p>Utilisez-la quand :</p><ul><li>vous activez la fédération pour la première fois ;</li><li>vous ajoutez de nouveaux fichiers à partager ;</li><li>vous changez les dossiers partagés ;</li><li>vous changez de domaine public.</li></ul><h2 id="rejoindre-d-autres-nœuds" tabindex="-1">Rejoindre d’autres nœuds <a class="header-anchor" href="#rejoindre-d-autres-nœuds" aria-label="Permalink to &quot;Rejoindre d’autres nœuds&quot;">​</a></h2><p><code>Nœuds rejoints</code> sert à suivre les nœuds d’autres sites ImgBed.</p><p><img src="`+s+'" alt="Nœuds rejoints" loading="lazy"></p><ol><li>Demandez un lien d’invitation au propriétaire de l’autre nœud.</li><li>Collez-le dans le champ.</li><li>Cliquez sur <code>Demander à rejoindre</code>.</li><li>Attendez l’approbation dans le panneau de l’autre personne.</li></ol><p>Après approbation, utilisez <code>Mettre à jour l’index entrant</code> pour synchroniser les fichiers partagés.</p><p>Pour mettre à jour un seul nœud, utilisez <code>Mettre à jour l’index</code> sur sa carte.</p><p><img src="'+r+'" alt="Mise à jour d’index" loading="lazy"></p><h2 id="gerer-les-demandes-vers-votre-nœud" tabindex="-1">Gérer les demandes vers votre nœud <a class="header-anchor" href="#gerer-les-demandes-vers-votre-nœud" aria-label="Permalink to &quot;Gérer les demandes vers votre nœud&quot;">​</a></h2><p><code>Demandes vers mon nœud</code> affiche les personnes qui souhaitent rejoindre votre nœud.</p><p><img src="'+a+'" alt="Demandes vers mon nœud" loading="lazy"></p><p>Pour générer une invitation, activez le nœud local, exécutez au moins une fois <code>Mettre à jour l’index sortant</code> pour confirmer le domaine public, puis cliquez sur <code>Réinitialiser le lien d’invitation</code>.</p><p>Lorsqu’une demande arrive, vous pouvez choisir :</p><table tabindex="0"><thead><tr><th>Action</th><th>Résultat</th></tr></thead><tbody><tr><td>Approuver</td><td>Autorise l’autre partie à synchroniser votre liste partagée</td></tr><tr><td>Refuser</td><td>Refuse l’entrée</td></tr><tr><td>Supprimer</td><td>Supprime un enregistrement terminé</td></tr><tr><td>Vérifier l’état</td><td>Vérifie si l’autre partie conserve la relation</td></tr></tbody></table><p>Après approbation, l’autre partie doit encore mettre à jour son index entrant pour voir vos fichiers.</p><p><img src="'+t+'" alt="Approuver un nœud" loading="lazy"></p><h2 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h2><p>Une fois la relation approuvée, vous pouvez utiliser <code>Message</code> sur la carte du nœud.</p><p>Les messages servent uniquement à échanger autour de la relation fédérée. Ils ne modifient ni fichiers, ni tags, ni dossiers, ni permissions.</p><p><img src="'+n+'" alt="Messages" loading="lazy"></p><h2 id="voir-les-fichiers-federes" tabindex="-1">Voir les fichiers fédérés <a class="header-anchor" href="#voir-les-fichiers-federes" aria-label="Permalink to &quot;Voir les fichiers fédérés&quot;">​</a></h2><p>Une fois la synchronisation terminée, revenez à la liste des fichiers du panneau. En haut de la page, vous pouvez basculer entre fichiers locaux et fichiers fédérés.</p><p>Les fichiers fédérés ne sont pas locaux : vous pouvez les consulter, les rechercher, les prévisualiser et copier leurs liens, mais pas les déplacer, les supprimer, modifier leurs tags ou les sauvegarder depuis votre site.</p><p><img src="'+o+'" alt="Affichage dans le panneau" loading="lazy"></p><h2 id="questions-frequentes" tabindex="-1">Questions fréquentes <a class="header-anchor" href="#questions-frequentes" aria-label="Permalink to &quot;Questions fréquentes&quot;">​</a></h2><h3 id="le-systeme-indique-qu-il-n-existe-pas-de-relation" tabindex="-1">Le système indique qu’il n’existe pas de relation <a class="header-anchor" href="#le-systeme-indique-qu-il-n-existe-pas-de-relation" aria-label="Permalink to &quot;Le système indique qu’il n’existe pas de relation&quot;">​</a></h3><p>Cela signifie généralement que l’autre partie a supprimé votre enregistrement. Envoyez une nouvelle demande.</p><p><img src="'+d+'" alt="Nouvelle demande" loading="lazy"></p><h3 id="je-suis-membre-mais-je-ne-vois-aucun-fichier" tabindex="-1">Je suis membre, mais je ne vois aucun fichier <a class="header-anchor" href="#je-suis-membre-mais-je-ne-vois-aucun-fichier" aria-label="Permalink to &quot;Je suis membre, mais je ne vois aucun fichier&quot;">​</a></h3><p>Vérifiez que :</p><ol><li>l’autre partie a approuvé votre demande ;</li><li>l’autre partie a mis à jour son index sortant ;</li><li>vous avez mis à jour l’index entrant ;</li><li>les dossiers synchronisés de l’autre partie contiennent bien les répertoires à partager.</li></ol>',55)])])}const j=l(h,[["render",m]]);export{_ as __pageData,j as default};
